u = CorpusUpgrader()
assert u.low_dim_encode("a b c d") == {"a": 1, "b": 1}
assert u.high_dim_encode("a b c") == {"a": 1, "b": 1, "c": 1}
assert u.high_dim_encode("a a b") == {"a": 2, "b": 1}
r = u.compare_retrieval("a b c", ["a b c d", "x y z"])
assert r["high_dim_top"] == "a b c d"
assert "low_dim_top" in r and "high_dim_top" in r
embs = u.re_embed(["test one", "test two"])
assert len(embs) == 2
for e in embs:
    mag = math.sqrt(sum(v**2 for v in e.values()))
    assert abs(mag - 1.0) < 0.001
